// 271. Encode and Decode Strings [Medium]
// https://leetcode.com/problems/encode-and-decode-strings/
// NOTE: LeetCode has no C++ starter for this problem (likely Premium).
// Solution sourced from NeetCode: https://raw.githubusercontent.com/neetcode-gh/leetcode/main/cpp/0271-encode-and-decode-strings.cpp

/*
    Design algorithm to encode/decode: list of strings <-> string

    Encode/decode w/ non-ASCII delimiter: {len of str, "#", str}

    Time: O(n)
    Space: O(1)
*/

class Codec {
public:

    // Encodes a list of strings to a single string.
    string encode(vector<string>& strs) {
        string result;

        for (const string& str : strs) {
            result.append(to_string(str.size()));
            result.push_back('#');
            result.append(str);
        }

        return result;
    }

    // Decodes a single string to a list of strings.
    vector<string> decode(string s) {
        vector<string> result;

        int i = 0;
        while (i < s.size()) {
            int j = i;
            while (s[j] != '#') {
                j++;
            }
            int length = stoi(s.substr(i, j - i));
            string str = s.substr(j + 1, length);
            result.push_back(str);
            i = j + 1 + length;
        }

        return result;
    }
private:
};

