// 252. Meeting Rooms [Easy]
// https://leetcode.com/problems/meeting-rooms/
// NOTE: LeetCode has no C++ starter for this problem (likely Premium).
// Solution sourced from NeetCode: https://raw.githubusercontent.com/neetcode-gh/leetcode/main/cpp/0252-meeting-rooms.cpp

/*
    Given array of time intervals, determine if can attend all meetings
    Ex. intervals = [[0,30],[5,10],[15,20]] -> false

    Sort by start time, check adj meetings, if overlap return false

    Time: O(n log n)
    Space: O(1)
*/

class Solution {
public:
    bool canAttendMeetings(vector<vector<int>>& intervals) {
        if (intervals.empty()) {
            return true;
        }

        sort(intervals.begin(), intervals.end());
        for (int i = 0; i < intervals.size() - 1; i++) {
            if (intervals[i][1] > intervals[i + 1][0]) {
                return false;
            }
        }
        return true;
    }
};

