  for (size_t i = 0; i < v.size(); ++i) { if (i) os << ','; __show(os, v[i]); }
  os << ']';
}
template <typename T>
static string __str(const T& v) { ostringstream os; __show(os, v); return os.str(); }

int main() {
  int __pass = 0, __total = 0;
  {
    ++__total;
    vector<int> __a0 = {2,0,2};
    vector<vector<int>> __a1 = {{0,2,1},{0,2,1},{1,1,3}};
    int __got = Solution().minZeroArray(__a0, __a1);
    ++__pass;
    cout << "case 1: ran   got=" << __str(__got) << "\n";
  }
  {
    ++__total;
    vector<int> __a0 = {4,3,2,1};
    vector<vector<int>> __a1 = {{1,3,2},{0,2,1}};
    int __got = Solution().minZeroArray(__a0, __a1);
    ++__pass;
    cout << "case 2: ran   got=" << __str(__got) << "\n";
  }
  cout << __pass << "/" << __total << " passed\n";
  return __pass == __total ? 0 : 1;
}
